#include <stdio.h>
int main() {
    int T, N, i, maxA, maxB, sumA, sumB;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int A[N], B[N];
        for (i = 0; i < N; i++) scanf("%d", &A[i]);
        for (i = 0; i < N; i++) scanf("%d", &B[i]);
        maxA = maxB = sumA = sumB = 0;
        for (i = 0; i < N; i++) {
            sumA += A[i];
            sumB += B[i];
            if (A[i] > maxA) maxA = A[i];
            if (B[i] > maxB) maxB = B[i];
        }
        sumA -= maxA;
        sumB -= maxB;
        if (sumA < sumB) printf("Alice\n");
        else if (sumA > sumB) printf("Bob\n");
        else printf("Draw\n");
    }
    return 0;
}

